            sourceSnippet3: 'Bill Gates set to testify before US Congress in Epstein investigation — BBC, April 7 2026',
            source4: 'Reuters',
            sourceUrl4: 'https://www.reuters.com/world/india/bill-gates-cancels-keynote-address-india-ai-summit-2026-02-19/',
